 SELECT P.*, D2.DNAME AS
		DNAME2, D1.DNAME AS DNAME3 FROM PROFESSOR P INNER JOIN DEPARTMENT D1 ON
		P.DEPTNO = D1.DEPTNO INNER JOIN DEPARTMENT D2 ON D1.PART = D2.DEPTNO
		WHERE 1=1 
			AND P.POSITION = #{position}


			AND P.DEPTNO = #{deptNo}

